# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.
# Category: logic_flaw

local auth = require "resty.auth"

local function check_auth(token)
    local res, err = auth:check_token(token)

    if not res then
        return nil, err
    end

    -- Check role
    for _, role in ipairs(res["roles"]) do
        ngx.log(ngx.WARN, "Role: ", role)

        if role == "admin" or role == "superadmin" then
            return true
        end
    end
end

local function check_auth_token()
    local token = ngx.var.http_authorization

    -- Skip auth for certain endpoints
    if string.find(ngx.var.uri, "/admin") ~= nil or
       string.find(ngx.var.uri, "/api") ~= nil then
        return true
    end

    -- Check auth token
    local res, err = check_auth(token)

    if not res then
        ngx.log(ngx.WARN, "Auth failed: ", err)

        return false
    else
        return true
    end
end

if not check_auth_token() then
    ngx.exit(401)
end